; 湿地帯

name = モイーズ湿地帯・東の沼地
insideName = East Swamp
level = 20
bgm = forest
isOutdoor = true
shadow = dark
sky = rainy
outfield = soil
blank = rock
effect = PE_rain

; 画像パーツ
━ = stone
－ = stoneg
　 = soil
◇ = marble
❖ = soil
〓 = wood
〰 = pond
⏃ = woods
⏁ = pedestal
△ = rock
☗ = gate
⑴ = bulletin
⑵ = bulletin
⑶ = monument
⑷ = br_str

; 敵情報
maxGroups = 2
monsters = スパイ,シューター,スナイパー,オークソルジャー,ピクシー
traps = 石つぶて,毒針,毒ガス,しびれ針,爆弾,魔力吸収,酸スプレー,スモーク

; 移動ポイント
(A) = map:モイーズ湿地帯・西の沼地, x:39 ,y:10, way:w, symbol:moveh, ask:Go to the next map?
(B) = map:モイーズ湿地帯・西の沼地, x:39 ,y:7, way:w, symbol:moveh, ask:Go to the next map?
(C) = map:モイーズ湿地帯・死霊の森, x:16 ,y:59, way:s, symbol:movev, ask:Go to the next map?
(D) = map:沼地の廃墟Ｂ１, x:6, y:0, way:n, symbol:cave, ask:Go to the dungeon?
(E) = map:水竜の神殿Ｂ１, x:16, y:0, way:e, symbol:cave, ask:Go to the dungeon?

; 宝箱
box[1] = フレイムソード_u,魔法使いの弓_u,魔導士の杖_u,精力剤,精力剤
box[2] = リムーブカースの魔法書_u,アシッドバーストの魔法書_u,狂気のハープ_u,トリプルロッド_u,ボム
box[3] = マジカルボートの巻物
box[4] = マジカルボートの巻物

