;-------------------------------------------------------------------------------
; マップを開いた時に必ず実行されるスクリプト
[initial]

[endinitial]
;===============================================================================
;◆イベント◆

; 初期発生イベント
events = [1, 2, 3, 4]

;-------------------------------------------------------------------------------
*event_1
;[exp] onObjectTrigger

@roadguide n="Swamp Ruins" e="Water Dragon Temple"

[eventoff]
;-------------------------------------------------------------------------------
*event_2
;[exp] onObjectTrigger

@roadguide s="Dead Forest"

[eventoff]
;-------------------------------------------------------------------------------
*event_3
;[exp] onObjectTrigger || (onUseEventItem && [o.エレメントプレート・土, o.エレメントプレート・水, o.エレメントプレート・火, o.エレメントプレート・風].has(game.curItem))

@eval exp='tf.temp = "eastSlotOnMonument"'
@jump storage="maze.map" target=*_set_plate_on_monument

[eventoff]
;-------------------------------------------------------------------------------
*event_4
;[exp] onObjectTrigger

@barrel
@damage v=&'game.curTarget.addParam("power", 2)'
@notice text=&'"<p>" + game.curTarget.displayName + "<w> had Strength permanently increased by 2!"'

[eventoff]
;-------------------------------------------------------------------------------
*event_5
;[exp] party.lastIsMove

; イベント時の移動制限。ダンジョンに入れないようにする
[texton]
[テオ f=06]「We should go somewhere else.」[k]
[textoff]
@walk move=s cond='game.party.curY == 22'
@walk move=e cond='game.party.curY == 31'

[eventoff]
;-------------------------------------------------------------------------------
